"""Skill Segmenter — groups events anchored by Skill tool calls."""

from __future__ import annotations

from typing import List, Optional

from traj_opt.adapter.schema import (
    EventType, TrajectoryEvent, Trajectory, TrajectoryType, ToolCall,
)
from traj_opt.segmenter.base import SegmenterStrategy


class SkillSegmenter(SegmenterStrategy):
    """Identifies skill-anchored trajectories.

    Scans for tool_name == "Skill" events and collects all subsequent tool calls
    until the next Skill call, turn boundary, or session end.
    """

    def name(self) -> str:
        return "skill"

    def segment(self, events: List[TrajectoryEvent]) -> List[Trajectory]:
        trajectories: List[Trajectory] = []
        current: Optional[_SkillGroup] = None

        for event in events:
            if event.event_type == EventType.TOOL_CALL and event.tool_name == "Skill":
                if current:
                    trajectories.append(current.to_trajectory())
                current = _SkillGroup(anchor=event)

            elif event.event_type == EventType.TOOL_CALL and current:
                current.add_event(event)

            elif event.event_type in (EventType.TURN_END, EventType.SESSION_END):
                if current:
                    trajectories.append(current.to_trajectory())
                    current = None

        if current:
            trajectories.append(current.to_trajectory())

        return trajectories


class _SkillGroup:
    """Accumulates events belonging to a single skill trajectory."""

    def __init__(self, anchor: TrajectoryEvent):
        self.anchor = anchor
        self.events: List[TrajectoryEvent] = [anchor]

    def add_event(self, event: TrajectoryEvent) -> None:
        self.events.append(event)

    def to_trajectory(self) -> Trajectory:
        skill_input = self.anchor.tool_input or {}
        skill_name = skill_input.get("skill", skill_input.get("name", "unknown"))
        skill_args = skill_input.get("args")

        tool_calls = [self._event_to_tool_call(e) for e in self.events]

        files: List[str] = []
        for e in self.events:
            for f in e.files_touched:
                if f not in files:
                    files.append(f)

        start_time = self.events[0].timestamp
        end_time = self.events[-1].timestamp
        duration_ms = (end_time - start_time).total_seconds() * 1000

        return Trajectory(
            trajectory_id=Trajectory.new_id(),
            session_id=self.anchor.session_id,
            conversation_id=self.anchor.conversation_id,
            trajectory_type=TrajectoryType.SKILL,
            layer=self.anchor.layer,
            skill_name=skill_name,
            skill_args=skill_args,
            tool_calls=tool_calls,
            start_time=start_time,
            end_time=end_time,
            duration_ms=duration_ms,
            files_touched=files,
        )

    @staticmethod
    def _event_to_tool_call(event: TrajectoryEvent) -> ToolCall:
        return ToolCall(
            tool_name=event.tool_name or "",
            tool_input=event.tool_input or {},
            tool_response=event.tool_response,
            timestamp=event.timestamp,
            success=event.success if event.success is not None else True,
            files_touched=event.files_touched,
        )

"""Analyzer base — infrastructure for LLM-based trajectory analysis.

The actual analysis logic lives in traj-analyze-* SKILL.md files.
This module provides utilities for reading trajectories and formatting reports.
"""

from __future__ import annotations

import json
from datetime import datetime, timezone
from pathlib import Path
from typing import Any, Dict, List, Optional

from traj_opt.adapter.schema import Trajectory, TrajectoryType
from traj_opt.store.reader import TrajectoryReader
from traj_opt.config import DEFAULT_CONFIG, TrajectoryConfig


class AnalyzerBase:
    """Provides trajectory reading and summary utilities for analysis skills."""

    def __init__(self, config: TrajectoryConfig = DEFAULT_CONFIG):
        self.config = config
        self.reader = TrajectoryReader(config)

    def get_rllm_trajectories(self, days: Optional[int] = None, session_id: Optional[str] = None) -> List[Trajectory]:
        """Get rllm-train related trajectories from Layer 1 (rllm)."""
        if session_id:
            all_trajs = self.reader.read_session_trajectories(session_id, layer="rllm")
        else:
            all_trajs = self.reader.read_recent_trajectories(days)
        return [
            t for t in all_trajs
            if (session_id or t.layer == "rllm")
            and t.trajectory_type == TrajectoryType.SKILL
            and t.skill_name
            and t.skill_name.startswith("rllm-")
        ]

    def get_traj_trajectories(self, days: Optional[int] = None) -> List[Trajectory]:
        """Get traj-loop related trajectories from Layer 2 (traj)."""
        all_trajs = self.reader.read_recent_trajectories(days)
        return [
            t for t in all_trajs
            if t.layer == "traj"
            and t.trajectory_type == TrajectoryType.SKILL
            and t.skill_name
            and t.skill_name.startswith("traj-")
        ]

    def get_skill_trajectories(self, skill_prefix: str, days: Optional[int] = None) -> List[Trajectory]:
        """Get trajectories for skills matching a prefix."""
        all_trajs = self.reader.read_recent_trajectories(days)
        return [
            t for t in all_trajs
            if t.trajectory_type == TrajectoryType.SKILL
            and t.skill_name
            and t.skill_name.startswith(skill_prefix)
        ]

    def summarize_trajectory(self, traj: Trajectory) -> Dict[str, Any]:
        """Create a concise summary of a trajectory for LLM consumption."""
        tool_summary: Dict[str, int] = {}
        for tc in traj.tool_calls:
            tool_summary[tc.tool_name] = tool_summary.get(tc.tool_name, 0) + 1

        failed_tools = [
            {"tool": tc.tool_name, "input": tc.tool_input}
            for tc in traj.tool_calls
            if not tc.success
        ]

        return {
            "session_id": traj.session_id,
            "trajectory_id": traj.trajectory_id,
            "type": traj.trajectory_type.value,
            "skill_name": traj.skill_name,
            "skill_args": traj.skill_args,
            "duration_ms": traj.duration_ms,
            "tool_count": len(traj.tool_calls),
            "tool_summary": tool_summary,
            "files_touched": traj.files_touched,
            "intent_tags": traj.intent_tags,
            "outcome": traj.outcome,
            "failed_tools": failed_tools,
        }

    def extract_training_data(self, traj: Trajectory) -> Dict[str, Any]:
        """Extract training data surfaced by rllm-monitor/rllm-analyze via tool calls."""
        result: Dict[str, Any] = {
            "config": None,
            "reward_trend": None,
            "perf_stats": None,
            "errors": [],
            "log_snippets": [],
        }

        for tc in traj.tool_calls:
            if tc.tool_name == "Read" and tc.tool_response:
                file_path = tc.tool_input.get("file_path", "")
                response_text = str(tc.tool_response)

                if "config.json" in file_path:
                    try:
                        result["config"] = json.loads(response_text)
                    except (json.JSONDecodeError, TypeError):
                        result["config"] = {"raw": response_text[:2000]}

                elif "perf_stats.json" in file_path:
                    try:
                        result["perf_stats"] = json.loads(response_text)
                    except (json.JSONDecodeError, TypeError):
                        result["perf_stats"] = {"raw": response_text[:2000]}

            elif tc.tool_name == "Bash" and tc.tool_response:
                command = tc.tool_input.get("command", "")
                response_text = str(tc.tool_response)

                if "training_log" in command or "tail" in command:
                    result["log_snippets"].append(response_text[:3000])
                    rewards = self._extract_rewards_from_log(response_text)
                    if rewards:
                        result["reward_trend"] = rewards

                if "Error" in response_text or "Traceback" in response_text:
                    result["errors"].append({
                        "command": command,
                        "error": response_text[:2000],
                    })

        return result

    def get_available_training_data(self, days: Optional[int] = None, session_id: Optional[str] = None) -> List[Dict[str, Any]]:
        """Get all rllm trajectories with extracted training data."""
        trajs = self.get_rllm_trajectories(days, session_id=session_id)
        results = []
        for traj in trajs:
            summary = self.summarize_trajectory(traj)
            training_data = self.extract_training_data(traj)
            results.append({**summary, "training_data": training_data})
        return results

    def _extract_rewards_from_log(self, log_text: str) -> Optional[List[Dict[str, Any]]]:
        """Extract step/reward pairs from training log text."""
        import re
        pattern = r'^\s*(\d+)/(\d+)\s+\d+\s+([\d.]+)'
        rewards = []
        for line in log_text.split('\n'):
            m = re.match(pattern, line)
            if m:
                rewards.append({
                    "step": int(m.group(1)),
                    "total": int(m.group(2)),
                    "reward": float(m.group(3)),
                })
        return rewards if rewards else None

    def format_for_llm(self, trajectories: List[Trajectory]) -> str:
        """Format trajectories as JSON for LLM analysis prompt."""
        summaries = [self.summarize_trajectory(t) for t in trajectories]
        return json.dumps(summaries, indent=2, ensure_ascii=False)

"""Free Segmenter — groups non-skill events by turn boundary and file affinity."""

from __future__ import annotations

from typing import Dict, List, Set

from traj_opt.adapter.schema import (
    EventType, IntentTag, TrajectoryEvent, Trajectory, TrajectoryType, ToolCall,
)
from traj_opt.segmenter.base import SegmenterStrategy


class FreeSegmenter(SegmenterStrategy):
    """Segments remaining (non-skill) events into free trajectories.

    Strategy:
    1. Split by turn boundaries (turn_end events)
    2. Within each turn, group by file affinity
    3. Tag intent based on tool patterns
    """

    def name(self) -> str:
        return "free"

    def segment(self, events: List[TrajectoryEvent]) -> List[Trajectory]:
        turns = self._split_by_turns(events)
        trajectories: List[Trajectory] = []

        for turn_events in turns:
            tool_events = [e for e in turn_events if e.event_type == EventType.TOOL_CALL]
            if not tool_events:
                continue

            groups = self._group_by_file_affinity(tool_events)
            for group in groups:
                traj = self._build_trajectory(group)
                trajectories.append(traj)

        return trajectories

    def _split_by_turns(self, events: List[TrajectoryEvent]) -> List[List[TrajectoryEvent]]:
        """Split events at turn_end boundaries."""
        turns: List[List[TrajectoryEvent]] = []
        current: List[TrajectoryEvent] = []

        for event in events:
            if event.event_type in (EventType.TURN_END, EventType.SESSION_END):
                if current:
                    turns.append(current)
                    current = []
            else:
                current.append(event)

        if current:
            turns.append(current)

        return turns

    def _group_by_file_affinity(self, events: List[TrajectoryEvent]) -> List[List[TrajectoryEvent]]:
        """Group events that touch overlapping files.

        Events that share file paths are grouped together. Events without files
        attach to the nearest group or form their own single-event group.
        """
        if not events:
            return []

        groups: List[List[TrajectoryEvent]] = []
        current_group: List[TrajectoryEvent] = [events[0]]
        current_files: Set[str] = set(events[0].files_touched)

        for event in events[1:]:
            event_files = set(event.files_touched)

            if event_files and current_files and event_files & current_files:
                current_group.append(event)
                current_files |= event_files
            elif not event_files and current_group:
                current_group.append(event)
            else:
                if current_group:
                    groups.append(current_group)
                current_group = [event]
                current_files = event_files

        if current_group:
            groups.append(current_group)

        return groups

    def _build_trajectory(self, events: List[TrajectoryEvent]) -> Trajectory:
        tool_calls = [
            ToolCall(
                tool_name=e.tool_name or "",
                tool_input=e.tool_input or {},
                tool_response=e.tool_response,
                timestamp=e.timestamp,
                success=e.success if e.success is not None else True,
                files_touched=e.files_touched,
            )
            for e in events
        ]

        files: List[str] = []
        for e in events:
            for f in e.files_touched:
                if f not in files:
                    files.append(f)

        start_time = events[0].timestamp
        end_time = events[-1].timestamp
        duration_ms = (end_time - start_time).total_seconds() * 1000

        intent_tags = self._infer_intent(events)

        return Trajectory(
            trajectory_id=Trajectory.new_id(),
            session_id=events[0].session_id,
            conversation_id=events[0].conversation_id,
            trajectory_type=TrajectoryType.FREE,
            layer=events[0].layer,
            tool_calls=tool_calls,
            start_time=start_time,
            end_time=end_time,
            duration_ms=duration_ms,
            files_touched=files,
            intent_tags=intent_tags,
        )

    def _infer_intent(self, events: List[TrajectoryEvent]) -> List[str]:
        """Infer intent tags from tool usage patterns."""
        tool_names = [e.tool_name for e in events if e.tool_name]
        tags: List[str] = []

        read_heavy = tool_names.count("Read") + tool_names.count("Bash") > len(tool_names) * 0.7
        has_edit = any(t in ("Edit", "Write") for t in tool_names)
        has_test_bash = any(
            e.tool_name == "Bash" and self._is_test_command(e.tool_input or {})
            for e in events
        )

        if has_edit:
            tags.append(IntentTag.IMPLEMENTATION.value)

        if has_test_bash:
            tags.append(IntentTag.TESTING.value)

        if has_edit and has_test_bash:
            tags.append(IntentTag.DEBUGGING.value)

        if read_heavy and not has_edit:
            tags.append(IntentTag.EXPLORATION.value)

        if not tags:
            tags.append(IntentTag.EXPLORATION.value)

        return tags

    @staticmethod
    def _is_test_command(tool_input: Dict) -> bool:
        command = tool_input.get("command", "")
        test_indicators = ["pytest", "test", "unittest", "npm test", "yarn test", "jest", "mocha"]
        return any(ind in command.lower() for ind in test_indicators)

"""Trajectory and event reader — queries stored data."""

from __future__ import annotations

import json
from datetime import datetime, timedelta, timezone
from pathlib import Path
from typing import List, Optional

from traj_opt.adapter.schema import TrajectoryEvent, Trajectory, SessionSummary
from traj_opt.config import DEFAULT_CONFIG, TrajectoryConfig


class EventReader:
    """Reads raw events from JSONL files."""

    def __init__(self, config: TrajectoryConfig = DEFAULT_CONFIG):
        self.config = config

    def read_session_events(self, session_id: str) -> List[TrajectoryEvent]:
        """Read all events for a session."""
        events_file = self.config.raw_dir / session_id / "events.jsonl"
        if not events_file.exists():
            return []
        return self._read_events_file(events_file)

    def list_sessions(self) -> List[str]:
        """List all session IDs that have raw events."""
        raw_dir = self.config.raw_dir
        if not raw_dir.exists():
            return []
        return sorted(
            d.name for d in raw_dir.iterdir()
            if d.is_dir() and (d / "events.jsonl").exists()
        )

    def read_recent_events(self, days: Optional[int] = None) -> List[TrajectoryEvent]:
        """Read events from recent sessions."""
        if days is None:
            days = self.config.analysis_lookback_days

        cutoff = datetime.now(timezone.utc) - timedelta(days=days)
        all_events: List[TrajectoryEvent] = []

        for session_id in self.list_sessions():
            events = self.read_session_events(session_id)
            if events and events[0].timestamp >= cutoff:
                all_events.extend(events)

        return all_events

    def _read_events_file(self, path: Path) -> List[TrajectoryEvent]:
        events: List[TrajectoryEvent] = []
        with open(path, "r", encoding="utf-8") as f:
            for line in f:
                line = line.strip()
                if not line:
                    continue
                try:
                    d = json.loads(line)
                    events.append(TrajectoryEvent.from_dict(d))
                except (json.JSONDecodeError, KeyError, ValueError):
                    continue
        return events


class TrajectoryReader:
    """Reads segmented trajectories."""

    def __init__(self, config: TrajectoryConfig = DEFAULT_CONFIG):
        self.config = config

    def read_session_trajectories(self, session_id: str, layer: Optional[str] = None) -> List[Trajectory]:
        """Read all trajectories for a session in a specific layer."""
        if layer is None:
            layer = self.config.layer

        traj_file = Path(self.config.output_dir) / layer / "trajectories" / session_id / "trajectories.jsonl"
        if not traj_file.exists():
            return []
        return self._read_trajectories_file(traj_file)

    def read_recent_trajectories(self, days: Optional[int] = None, layer: Optional[str] = None) -> List[Trajectory]:
        """Read trajectories from recent sessions across all layers or a specific layer."""
        if days is None:
            days = self.config.analysis_lookback_days

        cutoff = datetime.now(timezone.utc) - timedelta(days=days)
        all_trajs: List[Trajectory] = []

        layers = [layer] if layer else ["rllm", "traj", "meta"]

        for lyr in layers:
            for session_id in self.list_trajectory_sessions(lyr):
                trajs = self.read_session_trajectories(session_id, lyr)
                if trajs and trajs[0].start_time and trajs[0].start_time >= cutoff:
                    all_trajs.extend(trajs)

        return all_trajs

    def list_trajectory_sessions(self, layer: Optional[str] = None) -> List[str]:
        """List sessions that have segmented trajectories in a specific layer."""
        if layer is None:
            layer = self.config.layer

        traj_dir = Path(self.config.output_dir) / layer / "trajectories"
        if not traj_dir.exists():
            return []
        return sorted(
            d.name for d in traj_dir.iterdir()
            if d.is_dir() and (d / "trajectories.jsonl").exists()
        )

    def read_skill_trajectories(self, skill_name: str, days: Optional[int] = None) -> List[Trajectory]:
        """Read trajectories for a specific skill."""
        all_trajs = self.read_recent_trajectories(days)
        return [t for t in all_trajs if t.skill_name == skill_name]

    def _read_trajectories_file(self, path: Path) -> List[Trajectory]:
        trajectories: List[Trajectory] = []
        with open(path, "r", encoding="utf-8") as f:
            for line in f:
                line = line.strip()
                if not line:
                    continue
                try:
                    d = json.loads(line)
                    trajectories.append(Trajectory.from_dict(d))
                except (json.JSONDecodeError, KeyError, ValueError):
                    continue
        return trajectories

"""Round state coordination between CLI-1 (training) and CLI-2 (optimization).

Provides atomic read/write of per-round status files used to coordinate
the dual-CLI architecture. See docs/trajectory-design.md Section 18.
"""

from __future__ import annotations

import json
import os
import tempfile
from datetime import datetime, timezone
from pathlib import Path
from typing import Any, Dict, List, Optional


class RoundState:
    """Per-round status file manager. Used by both CLI-1 and CLI-2."""

    def __init__(self, base_dir: str = "traj_opt/output/rounds"):
        self.base_dir = Path(base_dir)

    def _status_path(self, round_num: int) -> Path:
        return self.base_dir / f"round_{round_num}" / "status.json"

    def _atomic_write(self, path: Path, data: Dict[str, Any]) -> None:
        path.parent.mkdir(parents=True, exist_ok=True)
        fd, tmp_path = tempfile.mkstemp(
            dir=str(path.parent), suffix=".tmp"
        )
        try:
            with os.fdopen(fd, "w") as f:
                json.dump(data, f, indent=2, ensure_ascii=False)
            os.rename(tmp_path, str(path))
        except Exception:
            try:
                os.unlink(tmp_path)
            except OSError:
                pass
            raise

    def write_training_complete(
        self,
        round_num: int,
        run_id: str,
        reward: float,
        session_id: str,
        run_ids: Optional[List[str]] = None,
        success: bool = True,
    ) -> str:
        """CLI-1: write status after training completes. Returns status file path."""
        now = datetime.now(timezone.utc).isoformat()
        path = self._status_path(round_num)

        data = self.read_status(round_num) or {}
        data.update({
            "round": round_num,
            "status": "training_complete" if success else "training_failed",
            "training": {
                "run_id": run_id,
                "run_ids": run_ids or [run_id],
                "session_id": session_id,
                "reward": reward,
                "success": success,
                "completed_at": now,
            },
            "updated_at": now,
        })
        data.setdefault("optimization", None)
        data.setdefault("created_at", now)

        self._atomic_write(path, data)
        return str(path)

    def write_training_failed(
        self,
        round_num: int,
        run_id: str,
        error: str,
        session_id: str,
        run_ids: Optional[List[str]] = None,
    ) -> str:
        """CLI-1: write status when training fails."""
        return self.write_training_complete(
            round_num=round_num,
            run_id=run_id,
            reward=0.0,
            session_id=session_id,
            run_ids=run_ids,
            success=False,
        )

    def write_optimization_complete(
        self,
        round_num: int,
        report_path: str,
        patches_generated: int,
        patches_accepted: int,
    ) -> str:
        """CLI-2: update status after optimization completes. Returns status file path."""
        now = datetime.now(timezone.utc).isoformat()
        path = self._status_path(round_num)

        data = self.read_status(round_num)
        if not data:
            raise FileNotFoundError(
                f"Round {round_num} status not found. CLI-1 must write training status first."
            )

        data["status"] = "optimization_complete"
        data["optimization"] = {
            "report_path": report_path,
            "patches_generated": patches_generated,
            "patches_accepted": patches_accepted,
            "completed_at": now,
        }
        data["updated_at"] = now

        self._atomic_write(path, data)
        return str(path)

    def read_status(self, round_num: int) -> Optional[Dict[str, Any]]:
        """Read status for a specific round. Returns None if not found."""
        path = self._status_path(round_num)
        if not path.exists():
            return None
        with open(path, "r", encoding="utf-8") as f:
            return json.load(f)

    def find_latest_round(self) -> Optional[int]:
        """Find the highest round number that has a status file."""
        if not self.base_dir.exists():
            return None
        rounds = []
        for d in self.base_dir.iterdir():
            if d.is_dir() and d.name.startswith("round_"):
                try:
                    rounds.append(int(d.name.split("_", 1)[1]))
                except (ValueError, IndexError):
                    continue
        return max(rounds) if rounds else None

    def find_pending_optimization(self) -> Optional[int]:
        """Find a round with status=training_complete (not yet optimized)."""
        if not self.base_dir.exists():
            return None
        for d in sorted(self.base_dir.iterdir(), reverse=True):
            if not d.is_dir() or not d.name.startswith("round_"):
                continue
            status_file = d / "status.json"
            if not status_file.exists():
                continue
            with open(status_file) as f:
                data = json.load(f)
            if data.get("status") == "training_complete":
                return data.get("round")
        return None

    def find_pending_training(self) -> Optional[int]:
        """Find the next round number after the latest optimization_complete."""
        latest = self.find_latest_round()
        if latest is None:
            return 1
        data = self.read_status(latest)
        if data and data.get("status") == "optimization_complete":
            return latest + 1
        return None

    def list_rounds(self) -> List[Dict[str, Any]]:
        """List all rounds with their status. For display purposes."""
        if not self.base_dir.exists():
            return []
        results = []
        for d in sorted(self.base_dir.iterdir()):
            if not d.is_dir() or not d.name.startswith("round_"):
                continue
            status_file = d / "status.json"
            if status_file.exists():
                with open(status_file) as f:
                    results.append(json.load(f))
        return results

